// Name implies only password checking, but secretly initializes session
public boolean checkPassword(String userName, String password) {
    User user = UserGateway.findByName(userName);
    if (user != null && isValid(user, password)) {
        Session.initialize(); // hidden side effect!
        return true;
    }
    return false;
}

CODE_EXAMPLE:
// Side effect made explicit in the name
public boolean checkPasswordAndInitializeSession(String userName, String password) {
    User user = UserGateway.findByName(userName);
    if (user != null && isValid(user, password)) {
        Session.initialize();
        return true;
    }
    return false;
}

// Or better: separate concerns
public boolean isValidPassword(String userName, String password) {
    User user = UserGateway.findByName(userName);
    return user != null && isValid(user, password);
}

UNIT_TEST_EXAMPLE:
@Test
public void isValidPassword_doesNotInitializeSession() {
    UserValidator validator = new UserValidator();
    boolean result = validator.isValidPassword("bob", "secret");
    assertFalse(Session.isInitialized());
}

@Test
public void isValidPassword_returnsTrueForCorrectCredentials() {
    UserValidator validator = new UserValidator();
    assertTrue(validator.isValidPassword("bob", "secret"));
}
